"""Export consolidated harness honesty Table 7 from generated audit artefacts."""

from __future__ import annotations

import csv
import json
from dataclasses import dataclass
from pathlib import Path
from typing import Literal

from pydantic import ValidationError

from dualexis.governance.formal_models import GovernanceAuditReport
from dualexis.leakage_audit.models import LeakageAuditReport
from dualexis.tsgg.trust_propagation import TrustPropagationReport

AUTO_GENERATED_BANNER = (
    "% Auto-generated by dualexis evaluation harness_honesty_export.\n"
    "% Do not edit manually; regenerate via: experiment export-harness-honesty\n"
)

SUGGESTED_COMMANDS = {
    "leakage_report": "python3.12 -m dualexis.cli experiment leakage-audit --fast",
    "privacy_fuzz_csv": "python3.12 -m dualexis.cli experiment validate-tsgg",
    "governance_report": "python3.12 -m dualexis.cli experiment formal-governance-audit",
    "trust_report": (
        "python3.12 -m dualexis.cli experiment tsgg-trust-propagation --fast --seeds 1,2,3"
    ),
}


class HarnessHonestyInputError(FileNotFoundError):
    """Missing artefact or required metric field for Table 7."""


@dataclass(frozen=True)
class HarnessHonestyMetrics:
    leakage_score: float
    procedural_independence: float
    distributional_independence: float
    ground_truth_stability_mean: float
    privacy_fuzz_pass_rate: float
    privacy_fuzz_probe_count: int
    governance_compliance_score: float
    decision_traceability: float
    mean_path_trust: float


@dataclass(frozen=True)
class HarnessHonestyPaths:
    leakage_report: Path = Path("results/leakage_audit/leakage_audit_report.json")
    privacy_fuzz_csv: Path = Path("results/privacy_fuzz/results.csv")
    governance_report: Path = Path("results/governance/formal/governance_audit_report.json")
    trust_report: Path = Path("results/tsgg/trust/trust_propagation_report.json")


def _require_file(path: Path, *, command_key: str) -> None:
    if not path.is_file():
        raise HarnessHonestyInputError(
            f"Missing required artefact: {path}. Run: {SUGGESTED_COMMANDS[command_key]}"
        )


def _parse_bool_cell(value: str) -> bool:
    normalized = value.strip().lower()
    if normalized in {"true", "1", "yes"}:
        return True
    if normalized in {"false", "0", "no"}:
        return False
    raise HarnessHonestyInputError(
        f"Cannot parse boolean pass value {value!r} in privacy fuzz CSV"
    )


def _validate_unit_interval(name: str, value: float) -> float:
    if not 0.0 <= value <= 1.0:
        raise HarnessHonestyInputError(f"{name} must be in [0, 1], got {value}")
    return value


def load_privacy_fuzz_pass_rate(
    csv_path: Path,
    *,
    expected_probe_count: int = 10,
) -> tuple[int, int, float]:
    """Return (passes, total, pass_rate) from privacy fuzz CSV."""
    _require_file(csv_path, command_key="privacy_fuzz_csv")
    with csv_path.open(encoding="utf-8", newline="") as handle:
        reader = csv.DictReader(handle)
        if reader.fieldnames is None or "pass" not in reader.fieldnames:
            raise HarnessHonestyInputError(
                f"{csv_path} must include a 'pass' column; regenerate privacy fuzz results"
            )
        rows = list(reader)

    if not rows:
        raise HarnessHonestyInputError(f"{csv_path} contains no fuzz probe rows")

    if len(rows) != expected_probe_count:
        raise HarnessHonestyInputError(
            f"{csv_path} expected {expected_probe_count} probes, found {len(rows)}"
        )

    passes = sum(1 for row in rows if _parse_bool_cell(row["pass"]))
    total = len(rows)
    pass_rate = round(passes / total, 4)
    return passes, total, _validate_unit_interval("privacy_fuzz_pass_rate", pass_rate)


def load_harness_honesty_metrics(
    paths: HarnessHonestyPaths | None = None,
    *,
    expected_fuzz_probes: int = 10,
) -> HarnessHonestyMetrics:
    """Load and validate all scalar metrics required for Table 7."""
    resolved = paths or HarnessHonestyPaths()

    _require_file(resolved.leakage_report, command_key="leakage_report")
    _require_file(resolved.governance_report, command_key="governance_report")
    _require_file(resolved.trust_report, command_key="trust_report")

    try:
        leakage = LeakageAuditReport.model_validate_json(
            resolved.leakage_report.read_text(encoding="utf-8")
        )
    except ValidationError as exc:
        raise HarnessHonestyInputError(
            f"Invalid leakage report at {resolved.leakage_report}: {exc}"
        ) from exc

    try:
        governance = GovernanceAuditReport.model_validate_json(
            resolved.governance_report.read_text(encoding="utf-8")
        )
    except ValidationError as exc:
        raise HarnessHonestyInputError(
            f"Invalid governance report at {resolved.governance_report}: {exc}"
        ) from exc

    try:
        trust_payload = json.loads(resolved.trust_report.read_text(encoding="utf-8"))
        trust = TrustPropagationReport.model_validate(trust_payload)
    except (json.JSONDecodeError, ValidationError) as exc:
        raise HarnessHonestyInputError(
            f"Invalid trust propagation report at {resolved.trust_report}: {exc}"
        ) from exc

    _, probe_count, pass_rate = load_privacy_fuzz_pass_rate(
        resolved.privacy_fuzz_csv,
        expected_probe_count=expected_fuzz_probes,
    )

    return HarnessHonestyMetrics(
        leakage_score=_validate_unit_interval(
            "leakage_score", leakage.leakage_score
        ),
        procedural_independence=_validate_unit_interval(
            "procedural_independence",
            leakage.independence.procedural_independence,
        ),
        distributional_independence=_validate_unit_interval(
            "distributional_independence",
            leakage.independence.distributional_independence,
        ),
        ground_truth_stability_mean=_validate_unit_interval(
            "ground_truth_stability_mean",
            leakage.ground_truth_stability_mean,
        ),
        privacy_fuzz_pass_rate=pass_rate,
        privacy_fuzz_probe_count=probe_count,
        governance_compliance_score=_validate_unit_interval(
            "governance_compliance_score",
            governance.metrics.governance_compliance_score,
        ),
        decision_traceability=_validate_unit_interval(
            "decision_traceability",
            governance.metrics.decision_traceability,
        ),
        mean_path_trust=_validate_unit_interval(
            "mean_path_trust",
            trust.metrics.mean_path_trust,
        ),
    )


def _format_gt_stability_footer(value: float) -> str:
    if abs(value - 0.5) < 0.05:
        return "0.5"
    return f"{value:.3f}"


def render_harness_honesty_latex(
    metrics: HarnessHonestyMetrics,
    *,
    caption_variant: Literal["artifact", "paper"] = "artifact",
) -> str:
    """Build LaTeX for tab:harness-honesty only."""
    if caption_variant == "paper":
        caption = (
            "Software validation disclosure summary on the synthetic harness "
            "(reference implementation). Scalar metrics are disjoint descriptors, "
            "not a composite quality score or readiness index."
        )
        statement_scope = "software-validation"
        traceability_phrase = "audit-chain completeness on simulated exports"
    else:
        caption = (
            "Framework-validation disclosure summary (Stage~S1 synthetic harness). "
            "Descriptive audit descriptors only; not operational outcomes, readiness, "
            "or system quality."
        )
        statement_scope = "framework-validation"
        traceability_phrase = "governance audit-chain completeness on simulated exports"

    gt_stability = _format_gt_stability_footer(metrics.ground_truth_stability_mean)
    lines = [
        AUTO_GENERATED_BANNER.rstrip("\n"),
        "",
        "\\begin{table}[htbp]",
        "  \\centering",
        f"  \\caption{{{caption}}}",
        "  \\label{tab:harness-honesty}",
        "  \\small",
        "  \\begin{tabular}{@{}p{5.9cm}r@{}}",
        "    \\toprule",
        "    Metric & Value \\\\",
        "    \\midrule",
        (
            "    Leakage score $L_S$ (higher = more coupling) & "
            f"{metrics.leakage_score:.3f} \\\\"
        ),
        (
            "    Procedural independence $\\pi_{\\mathrm{proc}}$ & "
            f"{metrics.procedural_independence:.3f} \\\\"
        ),
        (
            "    Distributional independence $\\pi_{\\mathrm{dist}}$ & "
            f"{metrics.distributional_independence:.3f} \\\\"
        ),
        (
            f"    Privacy fuzz pass rate ($N={metrics.privacy_fuzz_probe_count}$ probes) & "
            f"{metrics.privacy_fuzz_pass_rate:.3f} \\\\"
        ),
        (
            "    Governance compliance $\\gamma_{\\mathrm{comp}}$ & "
            f"{metrics.governance_compliance_score:.3f} \\\\"
        ),
        (
            "    Governance decision traceability $\\tau_{\\mathrm{trace}}$ & "
            f"{metrics.decision_traceability:.3f} \\\\"
        ),
        (
            "    Mean path trust $\\bar{T}_\\pi$ (trust propagation) & "
            f"{metrics.mean_path_trust:.3f} \\\\"
        ),
        "    \\bottomrule",
        "  \\end{tabular}",
        "  \\par\\vspace{0.4em}",
        (
            f"  {{\\footnotesize\\emph{{Statement:}}}} rows are disjoint {statement_scope} "
            "descriptors on the reference exporter, not a composite score. "
            "$\\pi_{\\mathrm{proc}}{=}1$ is a necessary code-separation check, not "
            "distributional independence ($\\pi_{\\mathrm{dist}}{=}"
            f"{metrics.distributional_independence:.3f}$; GT stability ${{\\approx}}"
            f"{gt_stability}$ under MC perturbation). $\\tau_{{\\mathrm{{trace}}}}$ is "
            f"{traceability_phrase}; "
            f"$\\gamma_{{\\mathrm{{comp}}}}$ is partial policy alignment "
            f"(${metrics.governance_compliance_score:.3f}$). "
            "$\\bar{T}_\\pi$ is compositional feasibility under A6, not operator trust. "
            "Results validate harness disclosure, not field utility."
        ),
        "\\end{table}",
        "",
    ]
    return "\n".join(lines)


def export_harness_honesty_tex(
    output_path: Path = Path("results_reference/tables/harness_honesty.tex"),
    *,
    metrics: HarnessHonestyMetrics | None = None,
    paths: HarnessHonestyPaths | None = None,
    caption_variant: Literal["artifact", "paper"] = "artifact",
    expected_fuzz_probes: int = 10,
) -> Path:
    """Write Table 7 LaTeX from metrics or loaded artefacts."""
    resolved_metrics = metrics or load_harness_honesty_metrics(
        paths,
        expected_fuzz_probes=expected_fuzz_probes,
    )
    target = output_path.resolve()
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(
        render_harness_honesty_latex(resolved_metrics, caption_variant=caption_variant),
        encoding="utf-8",
    )
    return target


__all__ = [
    "AUTO_GENERATED_BANNER",
    "HarnessHonestyInputError",
    "HarnessHonestyMetrics",
    "HarnessHonestyPaths",
    "export_harness_honesty_tex",
    "load_harness_honesty_metrics",
    "load_privacy_fuzz_pass_rate",
    "render_harness_honesty_latex",
]
